// === THE FORGED CHEQUE ANALOGY ===
//
// NORMAL DAY AT THE BANK:
// 1. You walk into bank (LOGIN) -- teller gives you a badge (SESSION COOKIE)
// 2. You fill out transfer form (FORM WITH YOUR DATA)
// 3. You hand form to teller (POST REQUEST)
// 4. Teller sees your badge, processes form (SERVER CHECKS SESSION)
//
// CSRF ATTACK:
// 1. You are at the bank, wearing your badge (LOGGED IN)
// 2. Someone slips a pre-filled form into your stack (EVIL SITE)
// 3. You unknowingly hand ALL forms to teller (BROWSER SENDS ALL)
// 4. Teller sees your badge on the forged form too (VALID SESSION)
// 5. Teller processes the forged transfer (ATTACK SUCCEEDS)
//
// THE FIX (CSRF TOKEN):
// The bank gives you a SECRET STAMP that only you know.
// Every form must have this stamp to be processed.
// The forger does not know your stamp -- their form is rejected!

import javax.servlet.*;
import javax.servlet.http.*;
import java.io.*;

public class TransferServlet extends HttpServlet {

    // Show the transfer form
    protected void doGet(HttpServletRequest request,
                         HttpServletResponse response)
            throws ServletException, IOException {

        HttpSession session = request.getSession(false);
        if (session == null || session.getAttribute("user") == null) {
            response.sendRedirect("/login");
            return;
        }

        response.setContentType("text/html");
        PrintWriter out = response.getWriter();
        out.println("<h2>Transfer Money</h2>");
        out.println("<form method='POST' action='/transfer'>");
        out.println("Amount: <input name='amount' type='number'><br>");
        out.println("To: <input name='to' type='text'><br>");
        out.println("<button type='submit'>Transfer</button>");
        out.println("</form>");
        // NO CSRF TOKEN -- VULNERABLE!
    }

    // Process the transfer
    protected void doPost(HttpServletRequest request,
                          HttpServletResponse response)
            throws ServletException, IOException {

        HttpSession session = request.getSession(false);
        if (session == null) {
            response.sendRedirect("/login");
            return;
        }

        String user = (String) session.getAttribute("user");
        String amount = request.getParameter("amount");
        String to = request.getParameter("to");

        // Process transfer -- NO CSRF CHECK!
        System.out.println("Transfer: " + user + " -> " + to + ": $" + amount);
        response.getWriter().println("Transfer successful!");
    }
}

