import java.security.SecureRandom;
import java.util.Base64;

public class CSRFTokenGenerator {

    private static final SecureRandom secureRandom = new SecureRandom();
    private static final int TOKEN_LENGTH = 32; // 256 bits

    /**
     * Generates a cryptographically secure CSRF token.
     * Uses SecureRandom for unpredictability and Base64 for safe encoding.
     */
    public static String generateToken() {
        byte[] bytes = new byte[TOKEN_LENGTH];
        secureRandom.nextBytes(bytes);
        return Base64.getUrlEncoder()
                     .withoutPadding()
                     .encodeToString(bytes);
    }

    public static void main(String[] args) {
        // Generate 5 tokens to show randomness
        System.out.println("=== CSRF Token Generator ===");
        for (int i = 1; i <= 5; i++) {
            String token = generateToken();
            System.out.println("Token " + i + ": " + token);
            System.out.println("  Length: " + token.length() + " chars");
            System.out.println("  Entropy: 256 bits");
        }

        // Show that tokens are always different
        String t1 = generateToken();
        String t2 = generateToken();
        System.out.println("\nTokens equal? " + t1.equals(t2));
    }
}

