import javax.servlet.http.*;

public class SecureCookieConfig {

    /**
     * Set session cookie with all security attributes.
     */
    public static void setSecureSessionCookie(
            HttpServletResponse response, String sessionId) {

        // Build cookie string with all security flags
        StringBuilder cookie = new StringBuilder();
        cookie.append("JSESSIONID=").append(sessionId);
        cookie.append("; Path=/");
        cookie.append("; HttpOnly");    // Prevents XSS reading cookie
        cookie.append("; Secure");      // HTTPS only
        cookie.append("; SameSite=Lax"); // CSRF protection
        cookie.append("; Max-Age=1800"); // 30 min timeout

        response.setHeader("Set-Cookie", cookie.toString());
    }

    public static void main(String[] args) {
        System.out.println("=== Cookie Security Comparison ===");
        System.out.println();

        // INSECURE cookie
        System.out.println("INSECURE:");
        System.out.println("Set-Cookie: JSESSIONID=abc123");
        System.out.println("  - No HttpOnly: XSS can steal it");
        System.out.println("  - No Secure: sent over HTTP (sniffable)");
        System.out.println("  - No SameSite: CSRF attacks work");
        System.out.println();

        // SECURE cookie
        System.out.println("SECURE:");
        System.out.println("Set-Cookie: JSESSIONID=abc123; "
            + "Path=/; HttpOnly; Secure; SameSite=Lax; Max-Age=1800");
        System.out.println("  - HttpOnly: JavaScript cannot read");
        System.out.println("  - Secure: HTTPS only");
        System.out.println("  - SameSite=Lax: blocks CSRF POST/AJAX");
        System.out.println("  - Max-Age: auto-expires in 30 min");
    }
}

import java.security.MessageDigest;
import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class CSRFAttackDetector {

    private List<String> attackLog = new ArrayList<>();
    private int blockedCount = 0;

    public boolean validateToken(String sessionToken, String requestToken,
                                 String clientIP, String endpoint) {

        // Case 1: No token provided (likely CSRF)
        if (requestToken == null || requestToken.isEmpty()) {
            logAttack("MISSING_TOKEN", clientIP, endpoint);
            return false;
        }

        // Case 2: No session token (session expired or new)
        if (sessionToken == null) {
            logAttack("SESSION_EXPIRED", clientIP, endpoint);
            return false;
        }

        // Case 3: Token mismatch (tampered or forged)
        if (!MessageDigest.isEqual(
                sessionToken.getBytes(), requestToken.getBytes())) {
            logAttack("TOKEN_MISMATCH", clientIP, endpoint);
            return false;
        }

        return true; // Valid
    }

    private void logAttack(String type, String ip, String endpoint) {
        blockedCount++;
        String entry = String.format("[%s] CSRF BLOCKED: %s from %s on %s",
            LocalDateTime.now(), type, ip, endpoint);
        attackLog.add(entry);
        System.out.println(entry);
    }

    public void printReport() {
        System.out.println("\n=== CSRF Attack Report ===");
        System.out.println("Total blocked: " + blockedCount);
        for (String entry : attackLog) {
            System.out.println("  " + entry);
        }
    }

    public static void main(String[] args) {
        CSRFAttackDetector detector = new CSRFAttackDetector();

        String validToken = "abc123secure";

        // Test 1: Valid request
        System.out.println("Test 1 (valid): " +
            detector.validateToken(validToken, validToken, "192.168.1.1", "/transfer"));

        // Test 2: Missing token (CSRF attack)
        System.out.println("Test 2 (missing): " +
            detector.validateToken(validToken, null, "10.0.0.5", "/transfer"));

        // Test 3: Wrong token (CSRF attack)
        System.out.println("Test 3 (wrong): " +
            detector.validateToken(validToken, "evil_token", "10.0.0.5", "/change-email"));

        // Test 4: Expired session
        System.out.println("Test 4 (expired): " +
            detector.validateToken(null, "some_token", "10.0.0.5", "/settings"));

        detector.printReport();
    }
}

import java.security.SecureRandom;
import java.util.Base64;
import java.security.MessageDigest;

public class DoubleSubmitCSRF {

    /**
     * Simulates Double Submit Cookie pattern.
     * Token is set as BOTH cookie AND form hidden field.
     * Server compares the two -- they must match.
     */

    static String generateToken() {
        byte[] bytes = new byte[32];
        new SecureRandom().nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    static boolean validate(String cookieToken, String formToken) {
        if (cookieToken == null || formToken == null) return false;
        return MessageDigest.isEqual(
            cookieToken.getBytes(), formToken.getBytes());
    }

    public static void main(String[] args) {
        // Server generates token
        String token = generateToken();
        System.out.println("Generated token: " + token.substring(0, 10) + "...");

        // Normal: both cookie and form have same token
        System.out.println("\n--- Legitimate Request ---");
        System.out.println("Cookie: csrf=" + token.substring(0, 10) + "...");
        System.out.println("Form:   csrf=" + token.substring(0, 10) + "...");
        System.out.println("Valid: " + validate(token, token));

        // Attack: attacker can make browser SEND cookie
        // but cannot READ it to put in form
        System.out.println("\n--- CSRF Attack ---");
        System.out.println("Cookie: csrf=" + token.substring(0, 10) + "... (sent automatically)");
        System.out.println("Form:   csrf=??? (attacker cannot read the cookie!)");
        System.out.println("Valid: " + validate(token, null));

        // Attack: attacker guesses wrong token
        String fakeToken = generateToken();
        System.out.println("\n--- Attack with Fake Token ---");
        System.out.println("Cookie: csrf=" + token.substring(0, 10) + "...");
        System.out.println("Form:   csrf=" + fakeToken.substring(0, 10) + "...");
        System.out.println("Valid: " + validate(token, fakeToken));
    }
}

import java.util.Arrays;
import java.util.List;

public class OriginValidator {

    private static final List<String> ALLOWED_ORIGINS = Arrays.asList(
        "https://mybank.com",
        "https://www.mybank.com"
    );

    public static String validateRequest(String origin, String referer,
                                         String method) {
        // GET requests are safe (read-only)
        if ("GET".equalsIgnoreCase(method)) {
            return "ALLOWED (safe method)";
        }

        // Check Origin header first (most reliable)
        if (origin != null && !origin.isEmpty()) {
            if (ALLOWED_ORIGINS.contains(origin)) {
                return "ALLOWED (valid origin: " + origin + ")";
            }
            return "BLOCKED (invalid origin: " + origin + ")";
        }

        // Fall back to Referer header
        if (referer != null && !referer.isEmpty()) {
            for (String allowed : ALLOWED_ORIGINS) {
                if (referer.startsWith(allowed + "/")) {
                    return "ALLOWED (valid referer)";
                }
            }
            return "BLOCKED (invalid referer: " + referer + ")";
        }

        // Both missing -- strict mode rejects
        return "BLOCKED (no origin or referer)";
    }

    public static void main(String[] args) {
        System.out.println("=== Origin Validation Tests ===");

        System.out.println("1. " + validateRequest(
            "https://mybank.com", null, "POST"));

        System.out.println("2. " + validateRequest(
            "https://evil-site.com", null, "POST"));

        System.out.println("3. " + validateRequest(
            null, "https://mybank.com/transfer", "POST"));

        System.out.println("4. " + validateRequest(
            null, "https://evil-site.com/attack", "POST"));

        System.out.println("5. " + validateRequest(
            null, null, "POST"));

        System.out.println("6. " + validateRequest(
            null, null, "GET"));
    }
}

import javax.servlet.*;
import javax.servlet.http.*;
import java.io.IOException;
import java.security.MessageDigest;
import java.security.SecureRandom;
import java.util.Base64;
import java.util.Arrays;
import java.util.List;

public class CSRFFilter implements Filter {

    private static final List<String> SAFE_METHODS =
        Arrays.asList("GET", "HEAD", "OPTIONS");
    private static final List<String> ALLOWED_ORIGINS =
        Arrays.asList("https://myapp.com");

    @Override
    public void doFilter(ServletRequest req, ServletResponse res,
                         FilterChain chain)
            throws IOException, ServletException {

        HttpServletRequest request = (HttpServletRequest) req;
        HttpServletResponse response = (HttpServletResponse) res;
        HttpSession session = request.getSession(true);

        // Ensure token exists
        if (session.getAttribute("csrf_token") == null) {
            session.setAttribute("csrf_token", generateToken());
        }

        String method = request.getMethod().toUpperCase();

        // Allow safe (read-only) methods
        if (SAFE_METHODS.contains(method)) {
            request.setAttribute("csrf_token",
                session.getAttribute("csrf_token"));
            chain.doFilter(req, res);
            return;
        }

        // Check Origin header
        String origin = request.getHeader("Origin");
        if (origin != null && !ALLOWED_ORIGINS.contains(origin)) {
            System.out.println("CSRF BLOCKED: Bad origin " + origin);
            response.sendError(403, "Invalid origin");
            return;
        }

        // Validate CSRF token
        String sessionToken = (String) session.getAttribute("csrf_token");
        String requestToken = request.getParameter("csrf_token");

        // Also check custom header (for AJAX)
        if (requestToken == null) {
            requestToken = request.getHeader("X-CSRF-Token");
        }

        if (sessionToken == null || requestToken == null ||
            !MessageDigest.isEqual(
                sessionToken.getBytes(), requestToken.getBytes())) {
            System.out.println("CSRF BLOCKED: Token mismatch on "
                + request.getRequestURI());
            response.sendError(403, "CSRF token invalid");
            return;
        }

        // Valid -- regenerate token
        session.setAttribute("csrf_token", generateToken());
        chain.doFilter(req, res);
    }

    private String generateToken() {
        byte[] bytes = new byte[32];
        new SecureRandom().nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding()
                     .encodeToString(bytes);
    }
}

// === LOGIN CSRF -- The Overlooked Attack ===
//
// Most developers protect transfers and settings.
// But what about the LOGIN form itself?
//
// Attack: attacker logs the victim into the ATTACKER's account.
//
// Why? If the victim thinks they are in their own account,
// they might:
// - Save their credit card (in attacker's account)
// - Upload private files (to attacker's cloud)
// - Enter personal info (stored in attacker's profile)

public class LoginCSRFDemo {
    public static void main(String[] args) {
        System.out.println("=== Login CSRF Attack ===");
        System.out.println();
        System.out.println("ATTACK STEPS:");
        System.out.println("1. Attacker creates account: evil@hacker.com / pass123");
        System.out.println("2. Attacker's page auto-submits login form:");
        System.out.println("   POST /login");
        System.out.println("   username=evil@hacker.com&password=pass123");
        System.out.println("3. Victim is now logged into ATTACKER's account");
        System.out.println("4. Victim saves credit card -> attacker's account");
        System.out.println("5. Victim uploads files -> attacker's cloud");
        System.out.println();
        System.out.println("DEFENCE:");
        System.out.println("- Add CSRF token to login form too");
        System.out.println("- Use pre-session tokens (before login)");
        System.out.println("- Show logged-in username prominently");
        System.out.println("- Require re-authentication for sensitive actions");
    }
}

// REST APIs have different CSRF considerations:
//
// 1. Cookie-based auth (session cookies) -> NEEDS CSRF protection
// 2. Token-based auth (Bearer token in header) -> CSRF-immune!
//
// Why? Bearer tokens are NOT sent automatically by the browser.
// The client JavaScript must explicitly add the Authorization header.
// An attacker's page cannot add headers to cross-origin requests.

public class APICSRFAnalysis {
    public static void main(String[] args) {
        System.out.println("=== REST API CSRF Analysis ===");
        System.out.println();

        System.out.println("COOKIE AUTH (vulnerable to CSRF):");
        System.out.println("  Request: POST /api/transfer");
        System.out.println("  Cookie: session=abc123  <- sent automatically!");
        System.out.println("  Body: {amount: 1000, to: evil}");
        System.out.println("  CSRF possible: YES");
        System.out.println();

        System.out.println("BEARER TOKEN AUTH (immune to CSRF):");
        System.out.println("  Request: POST /api/transfer");
        System.out.println("  Authorization: Bearer eyJhbGci...  <- NOT automatic!");
        System.out.println("  Body: {amount: 1000, to: evil}");
        System.out.println("  CSRF possible: NO");
        System.out.println("  (attacker cannot add Authorization header cross-origin)");
        System.out.println();

        System.out.println("MIXED AUTH (common in SPAs):");
        System.out.println("  Login creates session cookie (for page loads)");
        System.out.println("  API uses CSRF token in X-CSRF-Token header");
        System.out.println("  Both needed: cookie (auto) + token (manual)");
        System.out.println("  CSRF possible: NO (attacker cannot set custom header)");
    }
}

public class CSRFDefenceStrategy {
    public static void main(String[] args) {
        System.out.println("=== CSRF Defence in Depth ===");
        System.out.println();

        System.out.println("LAYER 1: SameSite Cookies");
        System.out.println("  Set-Cookie: session=...; SameSite=Lax; Secure; HttpOnly");
        System.out.println("  Blocks: POST/AJAX from other sites (automatic)");
        System.out.println("  Weakness: Old browsers, cookie injection");
        System.out.println();

        System.out.println("LAYER 2: CSRF Tokens");
        System.out.println("  Generate: SecureRandom 32 bytes, Base64");
        System.out.println("  Store: server session");
        System.out.println("  Send: hidden form field + X-CSRF-Token header");
        System.out.println("  Validate: constant-time comparison");
        System.out.println("  Blocks: All CSRF (attacker cannot read token)");
        System.out.println("  Weakness: XSS can read token from page");
        System.out.println();

        System.out.println("LAYER 3: Origin/Referer Checks");
        System.out.println("  Check: Origin header on all POST requests");
        System.out.println("  Fallback: Referer header");
        System.out.println("  Blocks: Cross-origin requests");
        System.out.println("  Weakness: Headers can be stripped");
        System.out.println();

        System.out.println("LAYER 4: Re-authentication");
        System.out.println("  For: password change, email change, transfers");
        System.out.println("  Require: current password or 2FA code");
        System.out.println("  Blocks: Even if CSRF succeeds, attacker needs password");
        System.out.println("  Weakness: None (strongest defence)");
        System.out.println();

        System.out.println("COMBINED: All 4 layers must be bypassed for attack.");
        System.out.println("This is Defence in Depth.");
    }
}

